import React from 'react';

const Card = ({ children, className = '', title, action, subtitle, icon: Icon, hover = false }) => {
  return (
    <div className={`bg-white rounded-xl shadow-sm border border-secondary-200 ${hover ? 'card-hover' : ''} ${className}`}>
      {(title || action) && (
        <div className="px-6 py-4 border-b border-secondary-100 flex items-center justify-between">
          <div className="flex items-center gap-3">
            {Icon && (
              <div className="w-10 h-10 bg-primary-50 rounded-lg flex items-center justify-center">
                <Icon className="w-5 h-5 text-primary-600" />
              </div>
            )}
            <div>
              {title && <h3 className="font-semibold text-secondary-800 text-lg">{title}</h3>}
              {subtitle && <p className="text-sm text-secondary-500 mt-0.5">{subtitle}</p>}
            </div>
          </div>
          {action && <div>{action}</div>}
        </div>
      )}
      <div className="p-6">{children}</div>
    </div>
  );
};

export default Card;
